const cfg            = require('../../config');
const { getBotName } = require('../../lib/botname');
const path           = require('path');
const fs             = require('fs');


// Inline banner image (base64-embedded — no external file needed)
const BANNER_IMG = Buffer.from('', 'base64');

const CAT_EMOJI = {
    utility:    '🔧',
    owner:      '👑',
    ai:         '🤖',
    group:      '👥',
    automation: '⚙️',
    channel:    '📢',
    download:   '📥',
    games:      '🎮',
    education:  '📚',
    spiritual:  '🕊️',
    fun:        '😂',
    sports:     '⚽',
    news:       '📰',
    stalker:    '🔍',
    image:      '🖼️',
    movie:      '🎬',
    search:     '🔎',
    adult:      '🔞',
};

// Built-in commands defined in index.js (not in toosi-cmds files)
// Note: 'av' removed here — it gets its own dedicated panel below
const BUILT_IN_EXTRAS = {
    owner:   ['ultimatefix', 'forcerestart', 'prefixinfo'],
    utility: ['statusstats', 'members'],
    group:   ['welcomeset'],
};

function loadCategories() {
    const cmdsDir = path.join(__dirname, '..');
    const cats    = {};
    const folders = fs.readdirSync(cmdsDir).filter(f => {
        try { return fs.statSync(path.join(cmdsDir, f)).isDirectory(); } catch { return false; }
    });
    for (const cat of folders) {
        const files = fs.readdirSync(path.join(cmdsDir, cat)).filter(f => f.endsWith('.js'));
        cats[cat] = [];
        for (const file of files) {
            try {
                const cmd = require(path.join(cmdsDir, cat, file));
                if (Array.isArray(cmd)) {
                    cmd.forEach(c => { if (c.name) cats[cat].push(c.name); });
                } else if (cmd.name) {
                    cats[cat].push(cmd.name);
                }
            } catch {}
        }
    }

    // Merge in built-in extras
    for (const [cat, cmds] of Object.entries(BUILT_IN_EXTRAS)) {
        if (!cats[cat]) cats[cat] = [];
        for (const cmd of cmds) {
            if (!cats[cat].includes(cmd)) cats[cat].push(cmd);
        }
    }

    return cats;
}

module.exports = {
    name: 'menu',
    aliases: ['help', 'commands', 'cmds'],
    description: 'Show all available commands',
    category: 'utility',
    async execute(sock, msg, args, prefix, ctx) {
        const chatId = msg.key.remoteJid;
        try { await sock.sendMessage(chatId, { react: { text: '🤖', key: msg.key } }); } catch {}
        const name   = getBotName();
        const rawMode = (process.env.BOT_MODE || cfg.MODE || 'public').toLowerCase();
        const modeMap = {
            public:  '🌐 Public',
            silent:  '🔇 Silent',
            groups:  '👥 Groups Only',
            dms:     '💬 DMs Only',
            buttons: '🔘 Buttons',
            channel: '📢 Channel',
            default: '🌐 Public',
        };
        const mode = modeMap[rawMode] || rawMode.toUpperCase();

        const now = new Date().toLocaleTimeString('en-US', {
            timeZone: cfg.TIME_ZONE,
            hour: '2-digit', minute: '2-digit',
        });

        // ── Stats ─────────────────────────────────────────────────
        const os      = require('os');
        const upSecs  = Math.floor(process.uptime());
        const upH     = Math.floor(upSecs / 3600);
        const upM     = Math.floor((upSecs % 3600) / 60);
        const upS     = upSecs % 60;
        const uptimeStr = `${upH}h ${upM}m ${upS}s`;

        const version = global.VERSION || cfg.VERSION || '1.1.5';

        // Ping: measure sendReact round-trip
        const pingStart = Date.now();
        try { await sock.sendMessage(chatId, { react: { text: '⚡', key: msg.key } }); } catch {}
        const pingMs = Date.now() - pingStart;

        const cats = loadCategories();
        const totalCmds = Object.values(cats).reduce((s, arr) => s + arr.length, 0);

        // ── RAM sampled last — after all async work — for freshest reading ──
        const _mem     = process.memoryUsage();
        const usedMB   = (_mem.rss / 1024 / 1024).toFixed(1);
        const totalGB  = (os.totalmem() / 1024 / 1024 / 1024).toFixed(2);
        // Bar = bot heap fill (heapUsed/heapTotal) — dynamic, reflects actual bot load
        const ramPct   = Math.min(100, Math.round((_mem.heapUsed / _mem.heapTotal) * 100));
        const filled   = Math.round(ramPct / 10);
        const ramBar   = '█'.repeat(filled) + '░'.repeat(10 - filled);

        let lines = [];

        // ── Header ──────────────────────────────────────────────
        lines.push(`╔═| ●-¤○《  ${name}  》○¤-●`);
        lines.push(`║`);
        lines.push(`║  ▸ ■  *Prefix*   :  ${prefix || 'none'}`);
        lines.push(`║  ▸ ■  *Owner*    :  ${cfg.OWNER_NUMBER || 'Unknown'}`);
        lines.push(`║  ▸ ■  *Mode*     :  ${mode}`);
        lines.push(`║  ▸ ■  *Version*  :  v${version}`);
        lines.push(`║  ▸ ■  *Platform* :  ☁️ Replit`);
        lines.push(`║  ▸ ■  *Speed*    :  ${pingMs}ms`);
        lines.push(`║  ▸ ■  *Uptime*   :  ${uptimeStr}`);
        lines.push(`║  ▸ ■  *Commands* :  ${totalCmds}`);
        lines.push(`║  ▸ ■  *Usage*    :  ${usedMB} MB of ${totalGB} GB`);
        lines.push(`║  ▸ ■  *RAM*      :  [${ramBar}] ${ramPct}%`);
        lines.push(`║  ▸ ■  *Time*     :  ${now}`);
        lines.push(`║`);
        lines.push(`║  👨‍💻  *Creator*    »  @toosiitech`);
        lines.push(`║  🔗  *Telegram*   »  t.me/toosiitech`);
        lines.push(`║`);

        // ── Categories ───────────────────────────────────────────
        const order  = ['utility', 'owner', 'ai', 'group', 'automation', 'channel', 'download', 'education', 'spiritual', 'fun', 'sports', 'news', 'stalker', 'image', 'movie', 'search', 'adult'];
        const sorted = [
            ...order.filter(k => cats[k]?.length),
            ...Object.keys(cats).filter(k => !order.includes(k) && cats[k]?.length),
        ];

        for (const cat of sorted) {
            const cmds = cats[cat];
            if (!cmds.length) continue;
            const emoji = CAT_EMOJI[cat] || '📌';
            lines.push(`╠═| ■-${emoji} ${cat.toUpperCase()} -■`);
            for (const cmd of cmds) {
                lines.push(`║  ◇ ${prefix}${cmd}`);
            }
            lines.push(`║`);
        }

        lines.push(`╚═╝`);

        // ── Attasa-style: image + caption together with channel forwarding header ──
        const sender        = msg.key.participant || msg.key.remoteJid;
        // Read live from process.env so .setnewsletter takes effect without restart
        const newsletterJid = process.env.NEWSLETTER_JID || cfg.NEWSLETTER_JID || '';
        const botName       = cfg.BOT_NAME || 'TOOSII-XD ULTRA';

        const contextInfo = {
            mentionedJid:  [sender],
            forwardingScore: 999,
            isForwarded:   true,
        };

        if (newsletterJid) {
            contextInfo.forwardedNewsletterMessageInfo = {
                newsletterJid,
                newsletterName:  botName,
                serverMessageId: 0,
            };
        }

        await sock.sendMessage(chatId, {
            image:       BANNER_IMG,
            mimetype:    'image/jpeg',
            caption:     lines.join('\n'),
            contextInfo,
        }, { quoted: msg });
    }
};
